(self.webpackChunk_N_E=self.webpackChunk_N_E||[]).push([[4282],{552:(e,t,a)=>{"use strict";a.r(t),a.d(t,{default:()=>h,useTOC:()=>s});var n=a(6514),r=a(7017),i=a(7291),o=a(9493);function s(e){return[{value:"School Days and Programming Contests",id:"school-days-and-programming-contests",depth:2},{value:"From Testing to Emulation",id:"from-testing-to-emulation",depth:2},{value:"The ZX Spectrum Next Challenge",id:"the-zx-spectrum-next-challenge",depth:2}]}let h=(0,r.e)(function(e){let{toc:t=s(e)}=e,a={h1:"h1",h2:"h2",p:"p",...(0,o.R)(),...e.components};return(0,n.jsxs)(n.Fragment,{children:[(0,n.jsx)(a.h1,{children:"Preface"}),"\n",(0,n.jsx)(a.p,{children:"Everyone has a personal story about their ZX Spectrum. Mine started before I even got my first Speccy. One day, my late father (I’m bearing his name, Istv\xe1n Nov\xe1k) brought back a TI-59 programmable calculator from his workspace. This wasn’t just a calculator—it had keys with mysterious text that went far beyond simple arithmetic. As a kid with an affection for math, I learned programming from its user guide. My father saw my enthusiasm and asked my uncle, Gy\xf6rgy Marczin (an electrical engineer), to help me improve."}),"\n",(0,n.jsx)(a.p,{children:"I live in Hungary. In 1981, when I was 13, Hungary was part of the communist bloc. My uncle, working for a large state-owned company, had the privilege of traveling to Western Europe. He saw the spark in me and helped me get a ZX81 from West Germany. Getting it wasn’t simple—my father had to buy Deutschmarks at the Hungarian black markets, since the Forint wasn’t convertible at the time."}),"\n",(0,n.jsx)(a.p,{children:"The 16K expansion pack for the ZX81 was great, but it became too small. Two years later, my father bought me a ZX Spectrum 48K. I went through the same awakening as countless others around the world who touched that rubber-keyed wonder."}),"\n",(0,n.jsx)(a.h2,{id:t[0].id,children:t[0].value}),"\n",(0,n.jsx)(a.p,{children:"We didn’t know it at the time, but in about seven years we’d have a revolution—a relatively peaceful transition from communism to something else. But we already had a technical revolution happening."}),"\n",(0,n.jsx)(a.p,{children:"In my first year at gymnasium (Berze Nagy J\xe1nos Gymnasium), HT-1080Z school computers (TRS-80 clones) became available for Hungarian students. We had four of them in my school! With other awakened buddies, we formed a small group that spent time in the computer lab before and after teaching hours. Another young electrical engineer, about 15 years older than us (Tibor Veres), coached us. Soon we were participating in—and winning—programming contests across Hungary."}),"\n",(0,n.jsx)(a.p,{children:"After the gymnasium, I became a software engineer at the Technical University of Budapest and earned a doctoral title in software technology."}),"\n",(0,n.jsx)(a.h2,{id:t[1].id,children:t[1].value}),"\n",(0,n.jsx)(a.p,{children:"At the beginning of the 2010s, I found myself as a freelance technology coach, helping software development teams and evangelizing automated testing. I needed something to demonstrate unit and integration testing. About ten years ago, one January morning, I woke up with a dream: let me go back to my childhood and create a ZX Spectrum emulator. Creating a high-fidelity emulator requires extensive automated tests—it would serve as the perfect example for designing and writing tests."}),"\n",(0,n.jsx)(a.p,{children:"And so, my first emulator was born: SpectNetIDE (written in C#), integrated into Visual Studio. Years later, when I coached teams on Web technologies, I started implementing Klive IDE, a TypeScript implementation."}),"\n",(0,n.jsx)(a.h2,{id:t[2].id,children:t[2].value}),"\n",(0,n.jsx)(a.p,{children:"I witnessed the ZX Spectrum revival with the ZX Spectrum Next. Though I missed the KS1 campaign, I have KS2 and (will have) KS3 machines. I felt a personal challenge to emulate this powerful successor in my Klive IDE."}),"\n",(0,n.jsx)(a.p,{children:"While working on the emulator, I learned a tremendous amount about this great machine from a programmer’s point of view: how its Z80N CPU, memory system, graphics layers, audio, storage, and timing features fit together when you actually want to make something run. The Next pushes boundaries—it’s not just nostalgia, it’s modern retro hardware done right."}),"\n",(0,n.jsx)(a.p,{children:"Let me share these learnings with the community."}),"\n",(0,n.jsx)(a.p,{children:"— Istv\xe1n Nov\xe1k"})]})},"/book/preface",{filePath:"pages/book/preface.mdx",timestamp:1778499692e3,pageMap:i.O,frontMatter:{},title:"Preface"},"undefined"==typeof RemoteContent?s:RemoteContent.useTOC)},4850:(e,t,a)=>{(window.__NEXT_P=window.__NEXT_P||[]).push(["/book/preface",function(){return a(552)}])}},e=>{e.O(0,[7017,7291,636,6593,8792],()=>e(e.s=4850)),_N_E=e.O()}]);